const orcamento = $json.body || {};
const calc = orcamento.dimensionamento_backup_calculado || {};
const inversor_modelo = calc.inversor_sugerido || '';
const nominal_kwh = calc.bateria_nominal_kwh || 0;

// Obter catálogo do passo anterior (HttpRequest retorna array no item anterior)
const catalogo = $items("Consultar Banco Equipamentos")[0].json || [];

// Localizar inversor no catálogo ou usar padrão
let inversor = catalogo.find(e => e.modelo === inversor_modelo && e.tipo === 'inversor_hibrido');
if (!inversor) {
  inversor = {
    modelo: inversor_modelo || 'SolaX X3-Hybrid 10.0-D',
    custo: null,
    status: 'pendente_validacao',
    fornecedor: 'Corsolar'
  };
}

// Localizar módulo de bateria padrão (5.8 kWh nominal)
let bateria_modelo = catalogo.find(e => e.tipo === 'bateria_litio' && e.capacidade_kwh === 5.8);
if (!bateria_modelo) {
  bateria_modelo = {
    modelo: 'Triple Power T-BAT H 5.8 (LFP)',
    capacidade_kwh: 5.8,
    custo: null,
    status: 'pendente_validacao',
    fornecedor: 'Corsolar'
  };
}

// Calcular quantidade de baterias (arredondar para cima)
const baterias_qtd = nominal_kwh > 0 ? Math.ceil(nominal_kwh / bateria_modelo.capacidade_kwh) : 0;

// Custos de referência estimados (comercial preliminar)
const custo_unit_inversor = inversor.custo || 14000.00; // Valor padrão se for null
const custo_unit_bateria = bateria_modelo.custo || 11000.00;

const custo_equipamentos = custo_unit_inversor + (custo_unit_bateria * baterias_qtd);
const logistica_impostos = custo_equipamentos * 0.12; // Estimativa de 12%
const custo_instalacao = 5000.00 + (baterias_qtd * 800); // Base Homem-Hora

const margem_bruta_porcentagem = 35; // Margem padrão comercial DL
const custo_total = custo_equipamentos + logistica_impostos + custo_instalacao;

// Preço de venda = custo total / (1 - margem)
const valor_final_estimado = Number((custo_total / (1 - (margem_bruta_porcentagem / 100))).toFixed(2));

return {
  ...orcamento,
  dimensionamento_backup_calculado: {
    ...calc,
    baterias_sugeridas: [
      {
        modelo: bateria_modelo.modelo,
        quantidade: baterias_qtd,
        capacidade_kwh: bateria_modelo.capacidade_kwh
      }
    ]
  },
  financeiro: {
    custos_estimados_equipamentos: custo_equipamentos,
    custo_instalacao_estimado: custo_instalacao,
    logistica_impostos,
    margem_bruta_porcentagem,
    valor_final_estimado
  },
  status: 'calculado_equipamentos'
};
